}

function servicosApp() {
  return {
    services: [],
    openFormService: false,
    formService: { id: '', nome: '', valor: '', duracao: '' },

    async init() {
      if (!localStorage.getItem('jwtToken')) {
        window.location.href = 'login.html'
        return
      }
      await this.fetchServices()
    },

    async fetchServices() {
      const cacheKey = 'cached_services'
      const cacheTime = 5 * 60 * 1000
      const cached = localStorage.getItem(cacheKey)
      const cachedData = cached ? JSON.parse(cached) : null

      if (cachedData && Date.now() - cachedData.timestamp < cacheTime) {
        this.services = cachedData.services
        return
      }

      try {
        const response = await fetch(
          getUrlBase()[getEnv()] + '/json/api/v1/services'
        )
        this.services = await response.json()
        this.services.sort((a, b) => a.nome.localeCompare(b.nome))

        localStorage.setItem(cacheKey, JSON.stringify({
          services: this.services,
          timestamp: Date.now(),
        }))
      } catch (error) {
        console.error('Erro ao buscar serviços:', error)
      }
    },

    invalidateServicesCache() {
      localStorage.removeItem('cached_services')
    },

    async postService() {
      try {
        const response = await fetch(
          getUrlBase()[getEnv()] + '/json/api/v1/services',
          {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              ...getAuthHeaders(),
            },
            body: JSON.stringify({
              id: this.formService.id,
              name: this.formService.nome.trim(),
              price: this.formService.valor,
              duration: this.formService.duracao,
              empresas_id: 1,
            }),
          }
        )

        if (handleAuthError(response)) return

        if (!response.ok) {
          const error = await response.json()
          alert('Erro: ' + (error.error || 'Falha ao salvar'))
          return
        }

        const newService = await response.json()
        this.invalidateServicesCache()
        this.services.push(newService.meta_input)
        this.services.sort((a, b) => a.nome.localeCompare(b.nome))
        this.formService = { id: '', nome: '', valor: '', duracao: '' }
        this.openFormService = false
      } catch (error) {
        console.error('Erro ao registrar serviço:', error)
      }
    },

    async deleteService(id) {
      if (!confirm('Tem certeza que deseja excluir este serviço?')) return

      try {
        const response = await fetch(
          getUrlBase()[getEnv()] + '/json/api/v1/services',
          {
            method: 'DELETE',
            headers: {
              'Content-Type': 'application/json',
              ...getAuthHeaders(),
            },
            body: JSON.stringify({ id }),
          }
        )

        if (handleAuthError(response)) return

        if (!response.ok) {
          const error = await response.json()
          alert('Erro: ' + (error.error || 'Falha ao excluir'))
          return
        }

        this.invalidateServicesCache()
        this.services = this.services.filter((s) => s.id !== id)
      } catch (error) {
        console.error('Erro ao excluir serviço:', error)
      }
    },
  }
}

function getUrlBase() {
  return {
    development: 'http://api-agendamento.teste',
    production: 'https://lightslategrey-guanaco-998055.hostingersite.com',
  }
}

function getEnv() {
  return 'development'
}

function getAuthHeaders() {
  return {
    'Authorization': 'Bearer ' + localStorage.getItem('jwtToken'),
  }
}

function handleAuthError(response) {
  if (response.status === 401) {
    localStorage.removeItem('jwtToken')
    window.location.href = 'login.html'
    return true
  }
  return false
}

function logout() {
  localStorage.removeItem('jwtToken')
  window.location.href = 'login.html'
}

function formatDate(date) {
  if (!date) return ''
  const [year, month, day] = date.split('-')
  return `${day}/${month}/${year}`
}

function formatCurrency(value) {
  if (!value && value !== 0) return ''
  return 'R$ ' + parseFloat(value).toFixed(2)
}

function getTodayLabel() {
  const now = new Date()
  const dias = ['Domingo', 'Segunda-feira', 'Terça-feira', 'Quarta-feira', 'Quinta-feira', 'Sexta-feira', 'Sábado']
  const meses = ['janeiro', 'fevereiro', 'março', 'abril', 'maio', 'junho', 'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro']
  return `${dias[now.getDay()]}, ${now.getDate()} de ${meses[now.getMonth()]} de ${now.getFullYear()}`
}

